  "maxcpu": 4,
  "maxmem": 8589934592,
  "maxdisk": 42949672960,
  "node": "pve1",
  "pool": "production"
}
</code></pre> <pre><code>class ProxmoxVM(BaseModel):
    vmid: int
    name: str
    type: Literal["qemu", "lxc"]
    status: str
    maxcpu: int
    maxmem: int                     # bytes
    maxdisk: int                    # bytes
    node: str
    pool: str | None = None

    @computed_field
    @property
    def memory_mb(self) -&gt; int:
        return self.maxmem // (1024 * 1024)

    @computed_field
    @property
    def disk_gb(self) -&gt; int:
        return self.maxdisk // (1024 ** 3)
</code></pre> <pre><code>{
  "name": "web-server-01",
  "cluster": 1,
  "status": "active",
